-- SCCD Booking — 正式設備清單 seed
-- 來源合併：id/分類/押金 = 「SCCD Platform alpha ver.」Equipments_Schedule；
--           名稱/總量/在庫/地點 = 「1. 設備預約現況」（營運帳本為準）。
-- Cube 依 Platform 歸類（同規格一項）；現況已無的品項未匯入；
-- 現況有而 Platform 未編號者依同規則補新代碼（機具 MG、搖頭燈 MH 等）。
-- 使用方式：SQL Editor 貼上執行一次。en_name 先留空；圖片暫用 mockup。

alter table public.equipment drop column if exists description;
alter table public.equipment add column if not exists en_name text;
alter table public.equipment add column if not exists sub_category text;
alter table public.equipment add column if not exists location text;
alter table public.equipment add column if not exists stock_quantity int not null default 0;

truncate table public.equipment cascade;

